def solve(has_dvt_signs, is_pe_primary, heart_rate_gt_100, has_immobilization_or_surgery, has_previous_pe_dvt, has_hemoptysis):
    # Step 1: evaluate_dvt_clinical_signs_score
    # Assign points for criterion 1: Clinical signs and symptoms of DVT.
    if has_dvt_signs:
        dvt_score = 3.0
    else:
        dvt_score = 0.0
    yield {
        "step_name": "evaluate_dvt_clinical_signs_score",
        "step_description": "Assign points for criterion 1: Clinical signs and symptoms of DVT.",
        "step_result": dvt_score,
        "unit": None
    }

    # Step 2: evaluate_pe_diagnosis_score
    # Assign points for criterion 2: PE is #1 diagnosis OR equally likely.
    if is_pe_primary:
        pe_diagnosis_score = 3.0
    else:
        pe_diagnosis_score = 0.0
    yield {
        "step_name": "evaluate_pe_diagnosis_score",
        "step_description": "Assign points for criterion 2: PE is #1 diagnosis OR equally likely.",
        "step_result": pe_diagnosis_score,
        "unit": None
    }

    # Step 3: evaluate_heart_rate_score
    # Assign points for criterion 3: Heart rate > 100.
    if heart_rate_gt_100:
        heart_rate_score = 1.5
    else:
        heart_rate_score = 0.0
    yield {
        "step_name": "evaluate_heart_rate_score",
        "step_description": "Assign points for criterion 3: Heart rate > 100.",
        "step_result": heart_rate_score,
        "unit": None
    }

    # Step 4: evaluate_immobilization_surgery_score
    # Assign points for criterion 4: Immobilization at least 3 days OR surgery in the previous 4 weeks.
    if has_immobilization_or_surgery:
        immobilization_score = 1.5
    else:
        immobilization_score = 0.0
    yield {
        "step_name": "evaluate_immobilization_surgery_score",
        "step_description": "Assign points for criterion 4: Immobilization at least 3 days OR surgery in the previous 4 weeks.",
        "step_result": immobilization_score,
        "unit": None
    }

    # Step 5: evaluate_previous_pe_dvt_score
    # Assign points for criterion 5: Previous, objectively diagnosed PE or DVT.
    if has_previous_pe_dvt:
        previous_pe_dvt_score = 1.5
    else:
        previous_pe_dvt_score = 0.0
    yield {
        "step_name": "evaluate_previous_pe_dvt_score",
        "step_description": "Assign points for criterion 5: Previous, objectively diagnosed PE or DVT.",
        "step_result": previous_pe_dvt_score,
        "unit": None
    }

    # Step 6: evaluate_hemoptysis_score
    # Assign points for criterion 6: Hemoptysis.
    if has_hemoptysis:
        hemoptysis_score = 1.0
    else:
        hemoptysis_score = 0.0
    yield {
        "step_name": "evaluate_hemoptysis_score",
        "step_description": "Assign points for criterion 6: Hemoptysis.",
        "step_result": hemoptysis_score,
        "unit": None
    }

    # Calculate total Wells' Criteria for PE score
    total_wells_pe_score = dvt_score + pe_diagnosis_score + heart_rate_score + immobilization_score + previous_pe_dvt_score + hemoptysis_score
    return total_wells_pe_score
